import{parentPort as r,workerData as n}from"worker_threads";import{Keypair as p}from"@solana/web3.js";import{generatePrivateKey as d,privateKeyToAccount as f}from"viem/accounts";import y from"bs58";var t=n,o=t.caseSensitive?t.prefix:t.prefix.toLowerCase(),e=0,i=500;if(t.chain==="solana")for(;;){let a=p.generate(),s=a.publicKey.toBase58();if(e++,(t.caseSensitive?s:s.toLowerCase()).startsWith(o)){r?.postMessage({type:"found",address:s,privateKey:y.encode(a.secretKey),attempts:e});break}e%i===0&&r?.postMessage({type:"progress",attempts:e})}else for(;;){let a=d(),s=f(a);if(e++,(t.caseSensitive?s.address:s.address.toLowerCase()).startsWith(o)){r?.postMessage({type:"found",address:s.address,privateKey:a,attempts:e});break}e%i===0&&r?.postMessage({type:"progress",attempts:e})}
